// ackInitList renders "false,false,false" for the Alpine array
// initialiser. Count is small (≤5); a slow-path loop is acceptable.
func ackInitList(n int) string {
	out := ""
	for i := 0; i < n; i++ {
		if i > 0 {
			out += ","
		}
		out += "false"
	}
	return out
}

